class Solution:
    def isNumber(self, s: str) -> bool:
        s = s.strip()
        if not s:
            return False
        seen_d = seen_dot = seen_e = False
        for i, c in enumerate(s):
            if c.isdigit():
                seen_d = True
            elif c in '+-':
                if i and s[i - 1] not in 'eE':
                    return False
            elif c in 'eE':
                if seen_e or not seen_d:
                    return False
                seen_e = True
                seen_d = False
                seen_dot = False
            elif c == '.':
                if seen_dot or seen_e:
                    return False
                seen_dot = True
            else:
                return False
        return seen_d

