class Solution {
public:
    bool isNumber(string s) {
        int i = 0, n = s.size();
        while (i < n && s[i] == ' ') i++;
        while (n > i && s[n - 1] == ' ') n--;
        if (i >= n) return false;
        bool d = false, dot = false, e = false;
        for (; i < n; i++) {
            if (isdigit(s[i])) d = true;
            else if (s[i] == '+' || s[i] == '-') {
                if (i && s[i - 1] != 'e' && s[i - 1] != 'E') return false;
            } else if (s[i] == 'e' || s[i] == 'E') {
                if (e || !d) return false;
                e = true; d = false; dot = false;
            } else if (s[i] == '.') {
                if (dot || e) return false;
                dot = true;
            } else return false;
        }
        return d;
    }
};

