int isNumber(char* s) {
    while (*s == ' ') s++;
    char* end = s + strlen(s);
    while (end > s && *(end - 1) == ' ') end--;
    if (s >= end) return 0;
    int d = 0, dot = 0, e = 0;
    for (char* p = s; p < end; p++) {
        if (*p >= '0' && *p <= '9') d = 1;
        else if (*p == '+' || *p == '-') {
            if (p > s && *(p - 1) != 'e' && *(p - 1) != 'E') return 0;
        } else if (*p == 'e' || *p == 'E') {
            if (e || !d) return 0;
            e = 1; d = 0; dot = 0;
        } else if (*p == '.') {
            if (dot || e) return 0;
            dot = 1;
        } else return 0;
    }
    return d;
}
